server {
    listen 8080;
    add_header Access-Control-Allow-Origin *;
    # Security headers
    add_header Strict-Transport-Security "max-age=31536000; includeSubdomains; preload";
    add_header X-Frame-Options SAMEORIGIN;
    add_header X-Content-Type-Options nosniff;
    add_header Set-Cookie "Path=/; HttpOnly; Secure";
    add_header Content-Security-Policy "default-src https://*.medimpact.com ; script-src https://*.medimpact.com https://*.googletagmanager.com  https://*.google-analytics.com 'self' 'unsafe-inline' ; connect-src  https://*.medimpact.com https://*.ice.ibmcloud.com https://*.verify.ibm.com https://*.googletagmanager.com  https://*.google-analytics.com 'self' ; img-src https://*.medimpact.com https://*.googletagmanager.com  https://*.google-analytics.com 'self'; style-src 'self' https://*.medimpact.com https://*.fontawesome.com 'unsafe-inline' ;base-uri 'self';form-action 'self';frame-ancestors 'self' https://*.medimpact.com; font-src 'self' https://*.fontawesome.com;";



    # Cache control headers

    # Cache for 6 hours.  Allow serving stale content if server down.
    #add_header Cache-Control "max-age=21600";

    # No cache in DEV
    add_header Cache-Control "no-cache, no-store, must-revalidate";

    root /app/dist;

    index index.html index.htm;

    location / {
        try_files $uri $uri/ /index.html;
    }
    location /healthz {
        access_log off;
        return 200 "healthy\n";
    }
}

