server {
    listen 8080;

    # Security headers
    add_header Access-Control-Allow-Origin *;
    add_header Strict-Transport-Security "max-age=31536000; includeSubdomains; preload";
    add_header X-Frame-Options SAMEORIGIN;
    add_header X-Content-Type-Options nosniff;
    # add_header Content-Security-Policy "default-src 'none'; script-src 'self'; connect-src 'self' https://*.medimpact.com https://*.ice.ibmcloud.com; img-src 'https://*.medimpact.com'; style-src 'self';base-uri 'self';form-action 'self';frame-ancestors 'self' https://*.medimpact.com;";
    add_header Content-Security-Policy "frame-ancestors 'self' *.medimpact.com";

    # Cache control headers
    # Cache for 24 hours.  Allow serving stale content if server down.
    add_header Cache-Control "max-age=86400";
    # No cache
    # add_header Cache-Control "no-cache, no-store, must-revalidate";

    port_in_redirect off;
    gzip on;
    gzip_vary on;
    gzip_min_length 256;
    gzip_types text/plain text/css text/javascript text/js  text/xml application/json application/javascript
        application/xml application/xml+rss image/svg+xml font/woff2 font/ttf;

    root /app/dist;
    index index.html index.htm;

    location /app-dashboard {
        alias /app/dist;
        try_files $uri $uri/ /index.html;
    }
    location /healthz {
        access_log off;
        return 200 "healthy\n";
    }
}

